normalized_obligations.lean_statement:
let counts := greedyCounts denoms amount;
  let obj (v : Fin denoms.size → ℕ) : ℕ := ∑ i in Finset.range denoms.size, v ⟨i, by simp⟩;
  obj counts = ∑ i in Finset.range denoms.size, counts ⟨i, by simp⟩

let counts := greedyCounts denoms amount;
  let obj (v : Fin denoms.size → ℕ) : ℕ := ∑ i in Finset.range denoms.size, v ⟨i, by simp⟩;
  ∀ v : Fin denoms.size → ℕ,
    (∑ i in Finset.range denoms.size, (v ⟨i, by simp⟩ * denoms[i])) = amount →
    obj counts ≤ obj v
